    func decryptMessage(sessionId: String, ephemeralPublicKey: [UInt8], messageNumber: UInt32, content: [UInt8]) throws  -> String
    
    func encryptMessage(sessionId: String, plaintext: String) throws  -> EncryptedMessageComponents
    
