#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeClassicCryptoCore: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = ClassicCryptoCore

    public static func lift(_ handle: UInt64) throws -> ClassicCryptoCore {
        return ClassicCryptoCore(unsafeFromHandle: handle)
    }

    public static func lower(_ value: ClassicCryptoCore) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ClassicCryptoCore {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: ClassicCryptoCore, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeClassicCryptoCore_lift(_ handle: UInt64) throws -> ClassicCryptoCore {
    return try FfiConverterTypeClassicCryptoCore.lift(handle)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeClassicCryptoCore_lower(_ value: ClassicCryptoCore) -> UInt64 {
    return FfiConverterTypeClassicCryptoCore.lower(value)
}






/**
 * Top-level orchestration facade.
 *
 * Swift / Kotlin call `handle_event_json` with a JSON-encoded `IncomingEvent`
 * and receive a JSON-encoded `Vec<Action>`. All I/O is delegated back to the
 * platform via these `Action` values.
 *
 * Replaces: CryptoManager + MessageRouter + SessionCoordinator + SessionHealingService
 *           + PersistentACKStore + PQCKeyManager + SessionInitializationService.
 */
public protocol OrchestratorCoreProtocol: AnyObject, Sendable {
    
    /**
     * Check if a message ID is in the in-memory ACK cache.
     */
    func ackIsProcessed(messageId: String)  -> AckCheckResult
    
    /**
     * Mark a message as processed in the ACK cache. Returns action JSON.
     */
    func ackMarkProcessed(messageId: String)  -> String
    
    func applyPqContribution(contactId: String, kemSharedSecret: [UInt8]) throws 
    
    func decryptMessage(contactId: String, ephemeralPublicKey: [UInt8], messageNumber: UInt32, content: [UInt8]) throws  -> String
    
    func encryptMessage(contactId: String, plaintext: String) throws  -> EncryptedMessageComponents
    
    /**
     * Export the PQContributionManager state as a CFE binary blob.
     * Persist under key "kyber_session_state" in the secure store.
     */
    func exportKyberSessionState() throws  -> [UInt8]
    
    func exportOneTimePrekeys() throws  -> [UInt8]
    
    func exportOneTimePrekeysJson() throws  -> String
    
    /**
     * Export the full orchestrator coordination state (ACK cache, healing queue,
     * init locks, archive index, prekey tracker) as a CFE binary blob.
     * Persist under key "orchestrator_state" in the secure store.
     */
    func exportOrchestratorState() throws  -> [UInt8]
    
    func exportPrivateKeys() throws  -> [UInt8]
    
    func exportPrivateKeysJson() throws  -> String
    
    func exportRegistrationBundleJson() throws  -> String
    
    func exportSession(contactId: String) throws  -> [UInt8]
    
    func exportSessionJson(contactId: String) throws  -> String
    
    /**
     * Export non-crypto orchestration state to JSON.
     */
    func exportStateJson() throws  -> String
    
    func generateOneTimePrekeys(count: UInt32) throws  -> [OtpkPair]
    
    func getAllSessionContactIds()  -> [String]
    
    /**
     * Raw identity secret key bytes (32 bytes, X25519).
     */
    func getIdentityKeyBytes() throws  -> Data
    
    /**
     * Typed registration bundle — replaces `export_registration_bundle_json()` parsing.
     */
    func getRegistrationBundleFields() throws  -> RegistrationBundleJson
    
    /**
     * Suite ID for the active session with `contact_id`.
     * Returns 0 if no session exists.
     */
    func getSessionSuiteId(contactId: String)  -> UInt16
    
    /**
     * Raw Ed25519 signing secret key bytes (64 bytes).
     */
    func getSigningKeyBytes() throws  -> Data
    
    /**
     * Typed event handler — replaces `handle_event_json`.
     * Accepts a typed `CfeIncomingEvent` and returns typed `CfeAction` list.
     */
    func handleEvent(event: CfeIncomingEvent) throws  -> [CfeAction]
    
    /**
     * Unified event handler (legacy JSON interface — kept for fallback).
     *
     * `event_json` — JSON-encoded `IncomingEvent` (see Rust `orchestration::actions`).
     * Returns a JSON array of `Action` objects for the platform to execute.
     */
    func handleEventJson(eventJson: String) throws  -> [String]
    
    func hasSession(contactId: String)  -> Bool
    
    /**
     * `true` iff `msg_number == 0` (healing-eligible message).
     */
    func healingCanHeal(msgNumber: UInt32)  -> Bool
    
    /**
     * Restore the PQContributionManager state from a CFE blob.
     */
    func importKyberSessionState(data: [UInt8]) throws 
    
    func importOneTimePrekeys(data: [UInt8]) throws 
    
    func importOneTimePrekeysJson(json: String) throws 
    
    /**
     * Restore the full orchestrator coordination state from a CFE blob.
     * Call at app start before processing any messages.
     */
    func importOrchestratorState(data: [UInt8]) throws 
    
    func importSession(contactId: String, data: [UInt8]) throws  -> String
    
    func importSessionJson(contactId: String, sessionJson: String) throws  -> String
    
    func initReceivingSession(contactId: String, recipientBundle: [UInt8], firstMessage: [UInt8]) throws  -> SessionInitResult
    
    func initSession(contactId: String, recipientBundle: [UInt8]) throws  -> String
    
    func oneTimePrekeyCount()  -> UInt32
    
    func prekeysAvailableCount()  -> UInt32
    
    /**
     * Register a KEM shared secret as a deferred contribution.
     * Returns JSON action string (SaveSessionToSecureStore for per-entry backup).
     */
    func registerPqDeferred(contactId: String, otpkId: UInt32, sharedSecret: [UInt8])  -> String
    
    func removeSession(contactId: String)  -> Bool
    
    func rotateSignedPrekey() throws  -> RotatedSpkBundle
    
    func setLocalUserId(userId: String) 
    
    func signBundleData(bundleDataJson: [UInt8]) throws  -> String
    
}
